/**
 * 高精度・自己完結型 複素FFTライブラリ (Cooley-Tukey アルゴリズム)
 * MIT License - Optimized for IR-Generator Project
 */
(function(global) {
    'use strict';

    function FFT(size) {
        if ((size & (size - 1)) !== 0) {
            throw new Error("FFTサイズは2の累乗（256, 512, 1024, 2048...）である必要があります。");
        }
        this.size = size;
        this.reverseTable = new Uint32Array(size);
        
        let limit = 1;
        let bit = size >> 1;
        while (limit < size) {
            for (let i = 0; i < limit; i++) {
                this.reverseTable[i + limit] = this.reverseTable[i] + bit;
            }
            limit <<= 1;
            bit >>= 1;
        }

        this.cosTable = new Float32Array(size / 2);
        this.sinTable = new Float32Array(size / 2);
        for (let i = 0; i < size / 2; i++) {
            let angle = (Math.PI * 2 * i) / size;
            this.cosTable[i] = Math.cos(angle);
            this.sinTable[i] = Math.sin(angle);
        }
    }

    FFT.prototype.forward = function(realIn, imagIn, realOut, imagOut) {
        const size = this.size;
        
        // ビット反転順に並び替えつつ初期化
        for (let i = 0; i < size; i++) {
            const rev = this.reverseTable[i];
            realOut[rev] = realIn[i];
            imagOut[rev] = imagIn ? imagIn[i] : 0.0;
        }

        // Cooley-Tukey バタフライ演算
        let halfSize = 1;
        while (halfSize < size) {
            const phaseShiftStepR = this.cosTable[size / (halfSize * 2) * (size / halfSize)]; // 厳密なインデックス参照の代替
            const step = halfSize << 1;
            
            for (let i = 0; i < size; i += step) {
                for (let j = 0; j < halfSize; j++) {
                    // テーブルから回転因子を正確に取得
                    const tableIdx = j * (size / step);
                    const wr = this.cosTable[tableIdx];
                    const wi = -this.sinTable[tableIdx]; // 順変換は e^(-i*theta)

                    const tr = realOut[i + j + halfSize] * wr - imagOut[i + j + halfSize] * wi;
                    const ti = realOut[i + j + halfSize] * wi + imagOut[i + j + halfSize] * wr;

                    realOut[i + j + halfSize] = realOut[i + j] - tr;
                    imagOut[i + j + halfSize] = imagOut[i + j] - ti;
                    realOut[i + j] += tr;
                    imagOut[i + j] += ti;
                }
            }
            halfSize = step;
        }
    };

    FFT.prototype.inverse = function(realIn, imagIn, realOut, imagOut) {
        const size = this.size;

        for (let i = 0; i < size; i++) {
            const rev = this.reverseTable[i];
            realOut[rev] = realIn[i];
            imagOut[rev] = imagIn[i];
        }

        let halfSize = 1;
        while (halfSize < size) {
            const step = halfSize << 1;
            for (let i = 0; i < size; i += step) {
                for (let j = 0; j < halfSize; j++) {
                    const tableIdx = j * (size / step);
                    const wr = this.cosTable[tableIdx];
                    const wi = this.sinTable[tableIdx]; // 逆変換は e^(i*theta)

                    const tr = realOut[i + j + halfSize] * wr - imagOut[i + j + halfSize] * wi;
                    const ti = realOut[i + j + halfSize] * wi + imagOut[i + j + halfSize] * wr;

                    realOut[i + j + halfSize] = realOut[i + j] - tr;
                    imagOut[i + j + halfSize] = imagOut[i + j] - ti;
                    realOut[i + j] += tr;
                    imagOut[i + j] += ti;
                }
            }
            halfSize = step;
        }

        // 逆変換のサイズ(N)による除算正規化
        for (let i = 0; i < size; i++) {
            realOut[i] /= size;
            imagOut[i] /= size;
        }
    };

    // グローバルオブジェクトへのエクスポート
    if (typeof module !== 'undefined' && module.exports) {
        module.exports = FFT;
    } else {
        global.ComplexFFT = FFT;
    }

})(typeof window !== 'undefined' ? window : this);
